function LxHttp:InternalGenWWWForm()
    local urlList = self._urlList
    local formList = {}
    local paramList = {}
    for k, url in ipairs(urlList) do
        local s,e = string.find(url, "?")
        local form = WWWForm.New()
        table.insert(formList, form)
        paramList[k] = ""
        if s then
            local params = string.sub(url, e + 1)
            paramList[k] = params

            local arrParam = string.split(params, "&")
            for _m,fieldStr in ipairs(arrParam) do
                local arrField = string.split(fieldStr, "=")
                local fieldKey = arrField[1]
                if not string.isempty(fieldKey) then
                    local fieldValue = string.sub(fieldStr, string.len(fieldKey) + 2)
                    --fieldValue = string.urldecode(fieldValue)
                    form:AddField(fieldKey, fieldValue)
                end
            end
            -- urlList[k] = string.sub(url, 0, s - 1)
        end
    end
    self._formList = formList
    self._formParamList = paramList
end

