    if self._isFixTimestamp then
        url = self:InternalFixTimestamp(url)
    end
    self._url = url
    self._form = self._formList and self._formList[curPos]
    if LOG_INFO_ENABLED then
        printInfo("Http", "<color=orange>send url : %s</color>", tostring(url))
        local params = self._formParamList and self._formParamList[curPos] or ""
        if not string.isempty(params) then
            params = string.gsub(params , "%%", "%%")
            printInfo("Http", "<color=green>send params : %s</color>",tostring(params))
        end
    end

    self:InternalInitRequest()

    self._request:SendWebRequest()
end

function LxHttp:InternalInitRequest()
    if self._request then
        self._request:Dispose()
        self._request = nil
    end
    local request
    local reqType = self._reqType
    if reqType == ReqType.Get then
        request = UnityWebRequest.Get(self._url)
    elseif reqType == ReqType.Download then
        if string.isempty(self._saveFile) then
            request = UnityWebRequest.Get(self._url)
        else
            request = UnityWebRequest.New(self._url, UnityWebRequest.kHttpVerbGET)
            local handler = DownloadHandlerFile.New(self._saveFile);
            handler.removeFileOnAbort = true;
            request.downloadHandler = handler;
        end
    elseif reqType == ReqType.Post then
        request = UnityWebRequest.Post(self._url, self._form)
        request:SetRequestHeader("Content-Type", "application/x-www-form-urlencoded;charset=UTF-8")
    elseif reqType == ReqType.PostByBody then
        request = UnityWebRequest.New(self._url, HttpMethod.Post)
        for _k, v in ipairs(self._headers or {}) do
            request:SetRequestHeader(v[1], v[2])
        end
        request.uploadHandler = UploadHandlerRaw.New(self._bodyBytes)
        request.downloadHandler = DownloadHandlerBuffer.New()
    elseif reqType == ReqType.Head then
        request = UnityWebRequest.Head(self._url)
    end

    request.certificateHandler = _instanceCertificateHandler

    request.timeout = self._timeout
    request.disposeDownloadHandlerOnDispose = true
    request.disposeUploadHandlerOnDispose = true
    request.disposeCertificateHandlerOnDispose = false
    self._request = request
end

