function LxHttp:InternalError()
    if LOG_ERROR_ENABLED then
        LogError("[Http] error | url="..tostring(self._url).. " | retry ("..self._retryPos.."/"..self._retryCount..")")
        LogError(self._error)
    end
    if self._retryPos >= self._retryCount then
        local okCb = self._okCb
        self._okCb = nil
        self._progressCb = nil
        if okCb then
            okCb(self._url, false, self._error)
        end
        return
    end
    self._nextRetryTime = Time.realtimeSinceStartup + _defaultRetryWaitTime
    self._status = HttpStatus.Retry
end

function LxHttp:OnUpdate()
    if self._isDisposed then return end

    if self._status == HttpStatus.Retry then
        if self._nextRetryTime < Time.realtimeSinceStartup then
            self:InternalSend()
        end
        return
    end

    if self._status ~= HttpStatus.Send then return end
    if not self._request then return end
    local result = self._request.result

    if result == HttpResult.InProgress then
        self:InternalProgress()

        if self._isCheckTimeout then
            self:CheckTimeOut()
        end

    elseif result == HttpResult.Success then
        self._status = HttpStatus.Done
        self:InternalSucceed()
    elseif result == HttpResult.ConnectionError or result == HttpResult.ProtocolError or result == HttpResult.DataProcessingError then
        self._status = HttpStatus.Error
        self._error = self._request.error
        self:InternalError()
    else
        if self._request.isDone then
            self._status = HttpStatus.Done
            self:InternalSucceed()
        end
    end
end

function LxHttp:CheckTimeOut()
    if not self._isAbort then
        self._downloadedBytes = self._request.downloadedBytes
        if  self._latestDownloadBytes ~= self._downloadedBytes then
            self._latestDownloadBytes = self._downloadedBytes
            self._latestDownloadRealtime = Time.realtimeSinceStartup
        end
        local  passTime = Time.realtimeSinceStartup - self._latestDownloadRealtime
        if passTime > self._timeout  then
            self._request:Abort()
            self._isAbort = true
        end
    end
end

